// RuntimeHandler is an implementation of the openotters.daemon.v1.Runtime service.
type RuntimeHandler interface {
	GetInfo(context.Context, *connect.Request[v1.GetInfoRequest]) (*connect.Response[v1.GetInfoResponse], error)
	BuildAgent(context.Context, *connect.Request[v1.BuildAgentRequest]) (*connect.Response[v1.BuildAgentResponse], error)
	BuildToolImage(context.Context, *connect.Request[v1.BuildToolImageRequest]) (*connect.Response[v1.BuildToolImageResponse], error)
	SaveAgentImage(context.Context, *connect.Request[v1.SaveAgentImageRequest]) (*connect.Response[v1.SaveAgentImageResponse], error)
	PullAgentImage(context.Context, *connect.Request[v1.PullRequest]) (*connect.Response[v1.PullResponse], error)
	PushAgentImage(context.Context, *connect.Request[v1.PushRequest]) (*connect.Response[v1.PushResponse], error)
	ListImages(context.Context, *connect.Request[v1.ListImagesRequest]) (*connect.Response[v1.ListImagesResponse], error)
	RefreshImage(context.Context, *connect.Request[v1.RefreshImageRequest]) (*connect.Response[v1.RefreshImageResponse], error)
	RemoveImage(context.Context, *connect.Request[v1.RemoveImageRequest]) (*connect.Response[v1.RemoveImageResponse], error)
	DescribeImage(context.Context, *connect.Request[v1.DescribeImageRequest]) (*connect.Response[v1.DescribeImageResponse], error)
	CreateAgent(context.Context, *connect.Request[v1.CreateAgentRequest]) (*connect.Response[v1.CreateAgentResponse], error)
	ListAgents(context.Context, *connect.Request[v1.ListAgentsRequest]) (*connect.Response[v1.ListAgentsResponse], error)
	StartAgent(context.Context, *connect.Request[v1.StartAgentRequest]) (*connect.Response[v1.StartAgentResponse], error)
	StopAgent(context.Context, *connect.Request[v1.StopAgentRequest]) (*connect.Response[v1.StopAgentResponse], error)
	RemoveAgent(context.Context, *connect.Request[v1.RemoveAgentRequest]) (*connect.Response[v1.RemoveAgentResponse], error)
	ChatWithAgent(context.Context, *connect.Request[v1.ChatRequest]) (*connect.Response[v1.ChatResponse], error)
	PromptObject(context.Context, *connect.Request[v1.PromptObjectRequest]) (*connect.Response[v1.PromptObjectResponse], error)
	ChatStreamWithAgent(context.Context, *connect.Request[v1.ChatStreamRequest], *connect.ServerStream[v1.ChatStreamEvent]) error
	ListSessionMessages(context.Context, *connect.Request[v1.ListSessionMessagesRequest]) (*connect.Response[v1.ListSessionMessagesResponse], error)
	ListSessions(context.Context, *connect.Request[v1.ListSessionsRequest]) (*connect.Response[v1.ListSessionsResponse], error)
	DeleteSession(context.Context, *connect.Request[v1.DeleteSessionRequest]) (*connect.Response[v1.DeleteSessionResponse], error)
	GetAgentLogs(context.Context, *connect.Request[v1.GetAgentLogsRequest]) (*connect.Response[v1.GetAgentLogsResponse], error)
	ListModels(context.Context, *connect.Request[v1.ListModelsRequest]) (*connect.Response[v1.ListModelsResponse], error)
	ListProviders(context.Context, *connect.Request[v1.ListProvidersRequest]) (*connect.Response[v1.ListProvidersResponse], error)
	AddProvider(context.Context, *connect.Request[v1.AddProviderRequest]) (*connect.Response[v1.AddProviderResponse], error)
	UpdateProvider(context.Context, *connect.Request[v1.UpdateProviderRequest]) (*connect.Response[v1.UpdateProviderResponse], error)
	RemoveProvider(context.Context, *connect.Request[v1.RemoveProviderRequest]) (*connect.Response[v1.RemoveProviderResponse], error)
	// ── async jobs ────────────────────────────────────────────────────
	// Submit a BIN job to run against the agent's spawn env. Jobs are
	// attached to the agent — not to a session. The daemon does not
	// push results anywhere on completion: observers (agent runtime,
	// operator CLI, UI) read via GetAsyncJob / WatchAsyncJob and
	// decide their own watch strategy.
	SubmitAsyncJob(context.Context, *connect.Request[v1.SubmitAsyncJobRequest]) (*connect.Response[v1.SubmitAsyncJobResponse], error)
	CancelAsyncJob(context.Context, *connect.Request[v1.CancelAsyncJobRequest]) (*connect.Response[v1.CancelAsyncJobResponse], error)
	GetAsyncJob(context.Context, *connect.Request[v1.GetAsyncJobRequest]) (*connect.Response[v1.GetAsyncJobResponse], error)
	ListAsyncJobs(context.Context, *connect.Request[v1.ListAsyncJobsRequest]) (*connect.Response[v1.ListAsyncJobsResponse], error)
	// ── notes (per-agent KV store) ───────────────────────────────────
	// Operator-facing CRUD for an agent's notes (durable facts the
	// model wrote via the note_* tools). Each RPC proxies to the per-
	// agent runtime's gRPC NotesService and surfaces NotFound /
	// FailedPrecondition cleanly to the UI.
	ListAgentNotes(context.Context, *connect.Request[v1.ListAgentNotesRequest]) (*connect.Response[v1.ListAgentNotesResponse], error)
	GetAgentNote(context.Context, *connect.Request[v1.GetAgentNoteRequest]) (*connect.Response[v1.GetAgentNoteResponse], error)
	SaveAgentNote(context.Context, *connect.Request[v1.SaveAgentNoteRequest]) (*connect.Response[v1.SaveAgentNoteResponse], error)
	DeleteAgentNote(context.Context, *connect.Request[v1.DeleteAgentNoteRequest]) (*connect.Response[v1.DeleteAgentNoteResponse], error)
	SetAgentNoteInContext(context.Context, *connect.Request[v1.SetAgentNoteInContextRequest]) (*connect.Response[v1.SetAgentNoteInContextResponse], error)
	// ── observability ────────────────────────────────────────────────
	// StreamRPCCalls tails the daemon's in-memory RPC ring buffer.
	// Operator-only (rejected for agent tokens). Always-on:
	// every Connect call hitting the daemon — including auth-failed
	// and future RPCs — is captured by the HTTP middleware without
	// any per-handler wiring; nothing is excluded except calls to
	// StreamRPCCalls itself (no feedback loop).
	StreamRPCCalls(context.Context, *connect.Request[v1.StreamRPCCallsRequest], *connect.ServerStream[v1.RPCCallEvent]) error
	// ── agent linking ───────────────────────────────────────────────
	// Operator-facing CRUD for the directed agent → agent call graph.
	// `otters link / unlink / links` map 1:1 to these RPCs. Auto-
	// restart of the source agent happens server-side on every
	// mutating call so the JWT (which carries the authoritative link
	// set) is always fresh.
	LinkAgents(context.Context, *connect.Request[v1.LinkAgentsRequest]) (*connect.Response[v1.LinkAgentsResponse], error)
	UnlinkAgents(context.Context, *connect.Request[v1.UnlinkAgentsRequest]) (*connect.Response[v1.UnlinkAgentsResponse], error)
	ListAgentLinks(context.Context, *connect.Request[v1.ListAgentLinksRequest]) (*connect.Response[v1.ListAgentLinksResponse], error)
	// Agent-facing cross-agent RPCs. Caller must present an agent
	// token; target must be in the JWT's Links claim. Enforced
	// inside the handlers via requireLinkedTarget. agent_chat was
	// removed in alpha.85 — its semantics (threaded session,
	// memory-preserving) are now agent_exec's default once a
	// session_id is supplied.
	AgentList(context.Context, *connect.Request[v1.AgentListRequest]) (*connect.Response[v1.AgentListResponse], error)
	AgentInfo(context.Context, *connect.Request[v1.AgentInfoRequest]) (*connect.Response[v1.AgentInfoResponse], error)
	AgentExec(context.Context, *connect.Request[v1.AgentExecRequest]) (*connect.Response[v1.AgentExecResponse], error)
	// Spawn / delete an agent and enumerate images / BIN images.
	// All four require an agent token (rejected for operator and
	// anonymous callers). agent_create rejects mounts and a
	// build-from-source path — those land on AgentCreateFromSource
	// and remain a separate capability operators opt into.
	// agent_delete is unrestricted: any authenticated agent caller
	// can delete any agent.
	AgentCreate(context.Context, *connect.Request[v1.AgentCreateRequest]) (*connect.Response[v1.AgentCreateResponse], error)
	AgentCreateFromSource(context.Context, *connect.Request[v1.AgentCreateFromSourceRequest]) (*connect.Response[v1.AgentCreateResponse], error)
	AgentDelete(context.Context, *connect.Request[v1.AgentDeleteRequest]) (*connect.Response[v1.AgentDeleteResponse], error)
	ImageList(context.Context, *connect.Request[v1.ImageListRequest]) (*connect.Response[v1.ImageListResponse], error)
	BinList(context.Context, *connect.Request[v1.BinListRequest]) (*connect.Response[v1.BinListResponse], error)
	// SelfReload re-issues the caller's JWT against the current
	// agent_links table and bounces the caller's runtime so the
	// refreshed token takes effect. Required after agent_create
	// when the caller included its own ref in `links` and wants
	// to call the new agent — without it, the JWT in memory
	// still carries the stale Links claim from agent startup.
	SelfReload(context.Context, *connect.Request[v1.SelfReloadRequest]) (*connect.Response[v1.SelfReloadResponse], error)
	// GetAgentIdentity exposes an agent's persisted JWT + decoded
	// claims for the operator UI's Identity tab. Operator-only
	// (rejected for agent tokens). The token field is the raw
	// signed JWT — the UI shows it behind a click-to-reveal toggle.
	GetAgentIdentity(context.Context, *connect.Request[v1.GetAgentIdentityRequest]) (*connect.Response[v1.GetAgentIdentityResponse], error)
	// Server-streaming watch: emits the current AsyncJob immediately,
	// then again on every material change (status, handle, exit_code,
	// stdout, stderr, error, started_at, finished_at), then closes the
	// stream when the job reaches a terminal status. NotFound at start
	// when the job doesn't exist. Implemented as a server-side poll
	// (~250 ms) — observers see at most ~250 ms latency from a status
	// flip to the corresponding stream message.
	WatchAsyncJob(context.Context, *connect.Request[v1.WatchAsyncJobRequest], *connect.ServerStream[v1.WatchAsyncJobResponse]) error
}

